var typedArrayByteLength = require('typed-array-byte-length');
var typedArrayByteOffset = require('typed-array-byte-offset');
var typedArrayLength = require('typed-array-length');
var whichTypedArray = require('which-typed-array');

var CloneArrayBuffer = require('./CloneArrayBuffer');
var GetValueFromBuffer = require('./GetValueFromBuffer');
var IsDetachedBuffer = require('./IsDetachedBuffer');
var IsSharedArrayBuffer = require('./IsSharedArrayBuffer');
var SameValue = require('./SameValue');
var SetValueInBuffer = require('./SetValueInBuffer');
var TypedArrayElementSize = require('./TypedArrayElementSize');
var TypedArrayElementType = require('./TypedArrayElementType');

var $ArrayBuffer = GetIntrinsic('%ArrayBuffer%', true);



module.exports = function SetTypedArrayFromTypedArray(target, targetOffset, source) {
	var whichTarget = whichTypedArray(target);
	if (!whichTarget) {
		throw new $TypeError('Assertion failed: target must be a TypedArray instance');
	}

	if (targetOffset !== Infinity && (!isInteger(targetOffset) || targetOffset < 0)) {
		throw new $TypeError('Assertion failed: targetOffset must be a non-negative integer or +Infinity');
	}

	var whichSource = whichTypedArray(source);
	if (!whichSource) {
		throw new $TypeError('Assertion failed: source must be a TypedArray instance');
	}

	var targetBuffer = typedArrayBuffer(target); 

	if (IsDetachedBuffer(targetBuffer)) {
		throw new $TypeError('target’s buffer is detached'); 
	}

	var targetLength = typedArrayLength(target); 

	var srcBuffer = typedArrayBuffer(source); 

	if (IsDetachedBuffer(srcBuffer)) {
		throw new $TypeError('source’s buffer is detached'); 
	}

	var targetType = TypedArrayElementType(target); 

	var targetElementSize = TypedArrayElementSize(target); 

	var targetByteOffset = typedArrayByteOffset(target); 

	var srcType = TypedArrayElementType(source); 

	var srcElementSize = TypedArrayElementSize(source); 

	var srcLength = typedArrayLength(source); 

	var srcByteOffset = typedArrayByteOffset(source); 

	if (targetOffset === Infinity) {
		throw new $RangeError('targetOffset must be a non-negative integer or +Infinity'); 
	}

	if (srcLength + targetOffset > targetLength) {
		throw new $RangeError('targetOffset + source.length must not be greater than target.length'); 
	}

	var targetContentType = whichTarget === 'BigInt64Array' || whichTarget === 'BigUint64Array' ? 'BigInt' : 'Number';
	var sourceContentType = whichSource === 'BigInt64Array' || whichSource === 'BigUint64Array' ? 'BigInt' : 'Number';
	if (targetContentType !== sourceContentType) {
		throw new $TypeError('source and target must have the same content type'); 
	}

	var sameSharedArrayBuffer = false;
	if (IsSharedArrayBuffer(srcBuffer) && IsSharedArrayBuffer(targetBuffer)) { 
		
		throw new $SyntaxError('SharedArrayBuffer is not supported by this implementation');
	}

	var srcByteIndex;
	if (SameValue(srcBuffer, targetBuffer) || sameSharedArrayBuffer) { 
		var srcByteLength = typedArrayByteLength(source); 

		srcBuffer = CloneArrayBuffer(srcBuffer, srcByteOffset, srcByteLength, $ArrayBuffer); 

		srcByteIndex = 0; 
	} else {
		srcByteIndex = srcByteOffset; 
	}

	var targetByteIndex = (targetOffset * targetElementSize) + targetByteOffset; 

	var limit = targetByteIndex + (targetElementSize * srcLength); 

	var value;
	if (srcType === targetType) { 
		

		while (targetByteIndex < limit) { 
			value = GetValueFromBuffer(srcBuffer, srcByteIndex, 'Uint8', true, 'Unordered'); 

			SetValueInBuffer(targetBuffer, targetByteIndex, 'Uint8', value, true, 'Unordered'); 

			srcByteIndex += 1; 

			targetByteIndex += 1; 
		}
	} else { 
		while (targetByteIndex < limit) { 
			value = GetValueFromBuffer(srcBuffer, srcByteIndex, srcType, true, 'Unordered'); 

			SetValueInBuffer(targetBuffer, targetByteIndex, targetType, value, true, 'Unordered'); 

			srcByteIndex += srcElementSize; 

			targetByteIndex += targetElementSize; 
		}
	}
};
